import{_ as n,o as a,c as i,ag as r}from"./chunks/framework.CvgP6Fyv.js";const b=JSON.parse('{"title":"Ausgaben","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/expenses.md","filePath":"de/features/expenses.md"}'),t={name:"de/features/expenses.md"};function s(l,e,o,u,g,h){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="ausgaben" tabindex="-1">Ausgaben <a class="header-anchor" href="#ausgaben" aria-label="Permalink to &quot;Ausgaben&quot;">​</a></h1><p>Verfolgen Sie alle Ihre Geschäftsausgaben, scannen Sie Belege mit KI und kategorisieren Sie Kosten für eine genaue Buchführung und USt.-Meldung.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Die Ausgabenseite listet alle Ihre erfassten Ausgaben auf. Filtern Sie nach:</p><ul><li><strong>Kategorie</strong> — Büro, Reise, Ausstattung usw.</li><li><strong>Projekt</strong> — Ausgaben, die mit bestimmten Projekten verknüpft sind</li><li><strong>Datumsbereich</strong> — Nach Ausgabendatum filtern</li><li><strong>Status</strong> — Aktiv oder archiviert</li></ul><h2 id="ausgabe-erstellen" tabindex="-1">Ausgabe erstellen <a class="header-anchor" href="#ausgabe-erstellen" aria-label="Permalink to &quot;Ausgabe erstellen&quot;">​</a></h2><h3 id="manuelle-eingabe" tabindex="-1">Manuelle Eingabe <a class="header-anchor" href="#manuelle-eingabe" aria-label="Permalink to &quot;Manuelle Eingabe&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Ausgaben &gt; Neue Ausgabe</strong></li><li>Füllen Sie aus: <ul><li><strong>Beschreibung</strong> — Wofür die Ausgabe ist</li><li><strong>Betrag</strong> — Gesamtkosten (inklusive oder exklusive USt.)</li><li><strong>Datum</strong> — Wann die Ausgabe angefallen ist</li><li><strong>Kategorie</strong> — Aus vordefinierten Kategorien auswählen</li><li><strong>USt.-Satz</strong> — Anwendbarer USt.-Prozentsatz</li></ul></li><li>Hängen Sie optional ein <strong>Beleg</strong>-Bild oder PDF an</li><li>Verknüpfen Sie optional mit einem <strong>Projekt</strong> oder <strong>Kunden</strong></li><li>Klicken Sie auf <strong>Speichern</strong></li></ol><h3 id="schnellerfassung" tabindex="-1">Schnellerfassung <a class="header-anchor" href="#schnellerfassung" aria-label="Permalink to &quot;Schnellerfassung&quot;">​</a></h3><p>Verwenden Sie die Schnellerfassungs-Schublade für schnelle Ausgabenerfassung:</p><ol><li>Klicken Sie auf die Schnellerfassungs-Schaltfläche auf der Ausgabenliste</li><li>Geben Sie Betrag und Beschreibung ein</li><li>Wählen Sie eine Schnellkategorie</li><li>Speichern</li></ol><h3 id="belegscanner" tabindex="-1">Belegscanner <a class="header-anchor" href="#belegscanner" aria-label="Permalink to &quot;Belegscanner&quot;">​</a></h3><p>Lassen Sie die KI Ausgabendetails automatisch aus Belegen extrahieren:</p><ol><li>Gehen Sie zu <strong>Ausgaben &gt; Beleg scannen</strong></li><li>Laden Sie ein Belegbild (JPEG, PNG, WebP) oder PDF hoch</li><li>Wählen Sie den Extraktionsmodus: <ul><li><strong>Einzeln</strong> — Eine Ausgabe aus dem Beleg</li><li><strong>Mehrfach</strong> — Mehrere Positionen aus einem Beleg</li></ul></li><li>Überprüfen Sie die extrahierten Daten (Datum, Betrag, Lieferant, Beschreibung)</li><li>Bestätigen Sie, um die Ausgabe(n) zu erstellen</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Belegscanner erfordert den <strong>Pro</strong>-Tarif oder höher.</p></div><h2 id="ausgabenkategorien" tabindex="-1">Ausgabenkategorien <a class="header-anchor" href="#ausgabenkategorien" aria-label="Permalink to &quot;Ausgabenkategorien&quot;">​</a></h2><p>MyCompanyDesk bietet vordefinierte Kategorien mit Symbolen zur schnellen Auswahl:</p><ul><li>Bürobedarf</li><li>Reise &amp; Transport</li><li>Essen &amp; Trinken</li><li>Software &amp; Abonnements</li><li>Ausstattung</li><li>Professionelle Dienstleistungen</li><li>Marketing &amp; Werbung</li><li>Versicherung</li><li>Miete &amp; Nebenkosten</li><li>Und mehr...</li></ul><p>Kategorien helfen bei der Organisation Ihrer Ausgaben und werden in Berichten für Kostenaufschlüsselungen verwendet.</p><h2 id="ust-behandlung" tabindex="-1">USt.-Behandlung <a class="header-anchor" href="#ust-behandlung" aria-label="Permalink to &quot;USt.-Behandlung&quot;">​</a></h2><p>Jede Ausgabe kann ihren eigenen USt.-Satz haben. Gängige Optionen:</p><ul><li><strong>21 %</strong> — Standardsatz</li><li><strong>9 %</strong> — Ermäßigter Satz</li><li><strong>0 %</strong> — Nullsatz oder befreit</li></ul><p>Der USt.-Betrag wird automatisch berechnet und in Ihre <a href="/de/features/vat">USt.-Berichte</a> aufgenommen.</p><h2 id="ausgaben-verknupfen" tabindex="-1">Ausgaben verknüpfen <a class="header-anchor" href="#ausgaben-verknupfen" aria-label="Permalink to &quot;Ausgaben verknüpfen&quot;">​</a></h2><p>Verknüpfen Sie Ausgaben mit:</p><ul><li><strong>Projekte</strong> — Projektkosten genau verfolgen</li><li><strong>Kunden</strong> — Kosten mit bestimmten Kunden verknüpfen</li><li><strong>Lieferanten</strong> — Erfassen, an wen Sie gezahlt haben</li></ul><h2 id="massenaktionen" tabindex="-1">Massenaktionen <a class="header-anchor" href="#massenaktionen" aria-label="Permalink to &quot;Massenaktionen&quot;">​</a></h2><p>Wählen Sie mehrere Ausgaben für:</p><ul><li><strong>Kategorisieren</strong> — Kategorie in großem Umfang ändern</li><li><strong>Archivieren</strong> — Ins Archiv verschieben</li><li><strong>Löschen</strong> — Dauerhaft entfernen</li><li><strong>Exportieren</strong> — Als CSV herunterladen</li></ul><h2 id="wiederkehrende-ausgaben" tabindex="-1">Wiederkehrende Ausgaben <a class="header-anchor" href="#wiederkehrende-ausgaben" aria-label="Permalink to &quot;Wiederkehrende Ausgaben&quot;">​</a></h2><p>Für regelmäßige Kosten (Miete, Abonnements usw.) richten Sie <a href="/de/features/recurring-expenses">wiederkehrende Ausgaben</a> ein, um die Erstellung zu automatisieren.</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><p>Importieren Sie Ausgaben aus CSV:</p><ol><li>Gehen Sie zu <strong>Profil &gt; Import</strong></li><li>Wählen Sie <strong>Ausgaben</strong> als Datentyp</li><li>Laden Sie Ihre CSV-Datei hoch</li><li>Ordnen Sie Spalten den Feldern zu</li><li>Überprüfen und bestätigen Sie</li></ol><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Aktivieren Sie <a href="/de/advanced/ai-features">KI-Vorschläge</a> für automatische Kategorieempfehlungen</li><li>Hängen Sie immer Belege an — sie sind für Steuerprüfungen unerlässlich</li><li>Verwenden Sie Projekte, um das Verhältnis von Ausgaben zu Einnahmen zu verfolgen</li><li>Prüfen Sie den <a href="/de/features/reports">Ausgabenbericht</a> für Ausgabenaufschlüsselungen</li></ul>',36)])])}const c=n(t,[["render",s]]);export{b as __pageData,c as default};
